# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.

Allowlist valid hosts/paths and validate universal link parameters before navigation or privileged actions.
# Category: insecure_universal_links

import UIKit

// MARK: - Models

struct PromoCode {
    let code: String
    let discountPercentage: Int
    
    var isValid: Bool {
        return !code.isEmpty && discountPercentage > 0 && discountPercentage <= 100
    }
}

enum PromoValidationError: Error, LocalizedError {
    case invalidHost
    case invalidPath
    case missingPromoCode
    case missingDiscount
    case invalidDiscountValue
    case discountOutOfRange
    case invalidPromoCodeFormat
    case expiredPromoCode
    case alreadyRedeemed
    case promoCodeNotFound
    
    var errorDescription: String? {
        switch self {
        case .invalidHost: return "The link is from an untrusted source."
        case .invalidPath: return "The link path is not recognized."
        case .missingPromoCode: return "No promo code was found in the link."
        case .missingDiscount: return "No discount value was found in the link."
        case .invalidDiscountValue: return "The discount value is not a valid number."
        case .discountOutOfRange: return "The discount must be between 1% and 100%."
        case .invalidPromoCodeFormat: return "The promo code format is invalid."
        case .expiredPromoCode: return "This promo code has expired."
        case .alreadyRedeemed: return "This promo code has already been redeemed."
        case .promoCodeNotFound: return "This promo code was not recognized."
        }
    }
}

// MARK: - Universal Link Validator

final class UniversalLinkValidator {
    
    // Allowlisted hosts
    private static let allowedHosts: Set<String> = [
        "myapp.com",
        "www.myapp.com"
    ]
    
    // Allowlisted paths
    private static let allowedPaths: Set<String> = [
        "/promo"
    ]
    
    // Allowed URL schemes
    private static let allowedSchemes: Set<String> = [
        "https"
    ]
    
    // Promo code regex: alphanumeric, 3-20 characters
    private static let promoCodePattern = "^[A-Za-z0-9]{3,20}$"
    
    static func validateHost(_ url: URL) -> Bool {
        guard let scheme = url.scheme?.lowercased(),
              allowedSchemes.contains(scheme) else {
            return false
        }
        guard let host = url.host?.lowercased(),
              allowedHosts.contains(host) else {
            return false
        }
        return true
    }
    
    static func validatePath(_ url: URL) -> Bool {
        let path = url.path.lowercased()
        return allowedPaths.contains(path)
    }
    
    static func validatePromoCodeFormat(_ code: String) -> Bool {
        let regex = try? NSRegularExpression(pattern: promoCodePattern)
        let range = NSRange(code.startIndex..., in: code)
        return regex?.firstMatch(in: code, range: range) != nil
    }
    
    static func extractAndValidatePromoParameters(from url: URL) -> Result<PromoCode, PromoValidationError> {
        // Step 1: Validate host
        guard validateHost(url) else {
            return .failure(.invalidHost)
        }
        
        // Step 2: Validate path
        guard validatePath(url) else {
            return .failure(.invalidPath)
        }
        
        // Step 3: Extract URL components
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return .failure(.missingPromoCode)
        }
        
        let queryItems = components.queryItems ?? []
        
        // Step 4: Extract and validate promo code
        guard let codeItem = queryItems.first(where: { $0.name == "code" }),
              let code = codeItem.value, !code.isEmpty else {
            return .failure(.missingPromoCode)
        }
        
        // Sanitize the code - trim whitespace
        let sanitizedCode = code.trimmingCharacters(in: .whitespacesAndNewlines)
        
        guard validatePromoCodeFormat(sanitizedCode) else {
            return .failure(.invalidPromoCodeFormat)
        }
        
        // Step 5: Extract and validate discount
        guard let discountItem = queryItems.first(where: { $0.name == "discount" }),
              let discountString = discountItem.value, !discountString.isEmpty else {
            return .failure(.missingDiscount)
        }
        
        guard let discountValue = Int(discountString) else {
            return .failure(.invalidDiscountValue)
        }
        
        guard discountValue >= 1 && discountValue <= 100 else {
            return .failure(.discountOutOfRange)
        }
        
        let promoCode = PromoCode(code: sanitizedCode.uppercased(), discountPercentage: discountValue)
        return .success(promoCode)
    }
}

// MARK: - Promo Service

protocol PromoServiceProtocol {
    func validatePromoCodeWithServer(promoCode: PromoCode, completion: @escaping (Result<PromoCode, PromoValidationError>) -> Void)
    func applyPromoToAccount(userId: String, promoCode: PromoCode, completion: @escaping (Result<Bool, Error>) -> Void)
}

final class PromoService: PromoServiceProtocol {
    
    static let shared = PromoService()
    
    // Simulated known valid promo codes (in production, this would be server-side)
    private let knownPromoCodes: Set<String> = ["XYZ", "SUMMER50", "WELCOME20", "VIP100"]
    private var redeemedCodes: [String: Set<String>] = [:] // userId -> Set of redeemed codes
    
    private init() {}
    
    func validatePromoCodeWithServer(promoCode: PromoCode, completion: @escaping (Result<PromoCode, PromoValidationError>) -> Void) {
        // Simulate network call
        DispatchQueue.global().asyncAfter(deadline: .now() + 0.5) { [weak self] in
            guard let self = self else { return }
            
            guard self.knownPromoCodes.contains(promoCode.code) else {
                DispatchQueue.main.async {
                    completion(.failure(.promoCodeNotFound))
                }
                return
            }
            
            DispatchQueue.main.async {
                completion(.success(promoCode))
            }
        }
    }
    
    func applyPromoToAccount(userId: String, promoCode: PromoCode, completion: @escaping (Result<Bool, Error>) -> Void) {
        DispatchQueue.global().asyncAfter(deadline: .now() + 0.5) { [weak self] in
            guard let self = self else { return }
            
            // Check if already redeemed
            if let userRedeemed = self.redeemedCodes[userId], userRedeemed.contains(promoCode.code) {
                DispatchQueue.main.async {
                    completion(.failure(PromoValidationError.alreadyRedeemed))
                }
                return
            }
            
            // Apply the promo code
            if self.redeemedCodes[userId] == nil {
                self.redeemedCodes[userId] = Set<String>()
            }
            self.redeemedCodes[userId]?.insert(promoCode.code)
            
            DispatchQueue.main.async {
                completion(.success(true))
            }
        }
    }
}

