// MARK: - Deep Link Router

final class DeepLinkRouter {
    
    static let shared = DeepLinkRouter()
    
    private init() {}
    
    enum DeepLinkDestination {
        case promo(PromoCode)
        case unknown
    }
    
    func route(url: URL, from viewController: UIViewController) {
        let destination = parseDestination(from: url)
        
        switch destination {
        case .promo(let promoCode):
            presentPromoScreen(promoCode: promoCode, from: viewController)
        case .unknown:
            showInvalidLinkAlert(from: viewController)
        }
    }
    
    private func parseDestination(from url: URL) -> DeepLinkDestination {
        let result = UniversalLinkValidator.extractAndValidatePromoParameters(from: url)
        
        switch result {
        case .success(let promoCode):
            return .promo(promoCode)
        case .failure(let error):
            print("Deep link validation failed: \(error.localizedDescription)")
            return .unknown
        }
    }
    
    private func presentPromoScreen(promoCode: PromoCode, from viewController: UIViewController) {
        let promoVC = PromoViewController(promoCode: promoCode)
        let navController = UINavigationController(rootViewController: promoVC)
        navController.modalPresentationStyle = .pageSheet
        
        if let sheet = navController.sheetPresentationController {
            sheet.detents = [.medium(), .large()]
            sheet.prefersGrabberVisible = true
        }
        
        viewController.present(navController, animated: true)
    }
    
    private func showInvalidLinkAlert(from viewController: UIViewController) {
        let alert = UIAlertController(
            title: "Invalid Link",
            message: "This promotional link is not valid or has expired. Please check the link and try again.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        viewController.present(alert, animated: true)
    }
}

